INSERT INTO cards.monsters VALUES (21, 'Ryu-kishin', 'DARK', NULL, '{Fiend,Normal}', 'A very elusive creature that looks like a harmless statue until it attacks.', 1000, 500, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/ryu-kishin.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.641', 5);
