INSERT INTO cards.monsters VALUES (25, 'Shadow Specter', 'DARK', NULL, '{Zombie,Normal}', 'Powerful in groups, this animal spirit can be found in the wastelands.', 500, 200, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/shadow-specter.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.643', 9);
