INSERT INTO cards.monsters VALUES (101, 'Dragon Zombie', 'DARK', NULL, '{Zombie,Normal}', 'A dragon revived by sorcery. Its breath is highly corrosive.', 1600, 0, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/dragon-zombie.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.678', 97);
