INSERT INTO cards.monsters VALUES (104, 'Battle Warrior', 'DARK', NULL, '{Warrior,Normal}', 'A grappling warrior who does not use any weapons and fights with bare hands.', 700, 1000, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/battle-warrior.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.679', 100);
INSERT INTO cards.monsters VALUES (105, 'Wings of Wicked Fl', 'DARK', NULL, '{Pyro,Normal}', 'The wings of this creature shimmer with red-black flames. It attacks by making fire erupt from all over its body.', 700, 600, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/wings-of-wicked-fl.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.679', 101);
INSERT INTO cards.monsters VALUES (108, 'Curtain of the Dar', 'DARK', NULL, '{Spellcaster,Normal}', 'A curtain woven by the hands of a sorcerer. It is said to enhance the power of magic users.', 600, 500, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/curtain-of-the-dar.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.68', 104);
INSERT INTO cards.monsters VALUES (109, 'Tomozaurus', 'DARK', NULL, '{Dinosaur,Normal}', 'Small but vicious, this monster even attacks its own kind.', 500, 400, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/tomozaurus.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.681', 105);
INSERT INTO cards.monsters VALUES (113, 'All-seeing Goddess', 'DARK', NULL, '{Fairy,Normal}', 'A goddess that has a divine third eye on her forehead. The divine eye gives her all-seeing powers.', 1200, 1000, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/all-seeing-goddess.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.682', 109);
