INSERT INTO cards.monsters VALUES (117, 'Dark Gray', 'DARK', NULL, '{Beast,Normal}', 'Entirely gray, this beast has rarely been seen by mortal eyes.', 800, 900, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/dark-gray.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.683', 113);
INSERT INTO cards.monsters VALUES (118, 'White Magical Hat', 'DARK', NULL, '{Spellcaster,Normal}', 'White silk hat and white tuxedo. Entire body is a pure-white thief.', 1000, 700, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/white-magical-hat.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.684', 114);
INSERT INTO cards.monsters VALUES (120, 'Nightmare Scorpion', 'DARK', NULL, '{Insect,Normal}', 'A creature that generates nightmares to haunt an opponent, it attacks with four poisonous tails.', 900, 800, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/nightmare-scorpion.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.685', 116);
INSERT INTO cards.monsters VALUES (82, 'Grappler', 'DARK', NULL, '{Reptile,Normal}', 'A devious snake with a thick body that wraps around an enemy monster and squeezes the life out of it.', 1300, 1200, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/grappler.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.686', 77);
INSERT INTO cards.monsters VALUES (83, 'Axe Raider', 'DARK', NULL, '{Warrior,Normal}', 'An axe-wielding monster of tremendous strength and agility.', 1700, 1150, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/axe-raider.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.686', 78);
INSERT INTO cards.monsters VALUES (107, 'Job-change Mirror', 'DARK', NULL, '{Fiend,Normal}', 'A wicked mirror that blocks off the damaging effects of an attack.', 800, 1300, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/job-change-mirror.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.687', 103);
INSERT INTO cards.monsters VALUES (111, 'Kageningen', 'DARK', NULL, '{Warrior,Normal}', 'Uses both physical and shadow forms to attack, making it a difficult creature to overcome.', 800, 600, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/kageningen.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.687', 107);
INSERT INTO cards.monsters VALUES (129, 'Faith Bird', 'DARK', NULL, '{WingedBeast,Normal}', 'This long-tailed bird blinds its enemies with mystical light.', 1500, 1100, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/faith-bird.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.689', 125);
INSERT INTO cards.monsters VALUES (131, 'Ansatsu', 'DARK', NULL, '{Warrior,Normal}', 'A silent and deadly warrior specializing in assassinations.', 1700, 1200, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/ansatsu.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.689', 127);
