INSERT INTO cards.monsters VALUES (146, 'Necrolancer', 'DARK', NULL, '{Spellcaster,Normal}', 'The first in a line of lords that appear from a space-time ring that can appear anywhere.', 800, 900, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/necrolancer.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.695', 143);
