INSERT INTO cards.monsters VALUES (156, 'Dokuroizo the Grim', 'DARK', NULL, '{Zombie,Normal}', 'A grim reaper that steals souls with hellish slashes.', 900, 1200, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/dokuroizo-the-grim.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.698', 153);
INSERT INTO cards.monsters VALUES (159, 'Hard Armor', 'DARK', NULL, '{Warrior,Normal}', 'A living suit of armor that attacks enemies with a bone-jarring tackle.', 300, 1200, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/hard-armor.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.698', 156);
