INSERT INTO cards.monsters VALUES (162, 'Dig Beak', 'DARK', NULL, '{Beast,Normal}', 'This beast coils like a snake, and strikes quickly with its snapping beak.', 500, 800, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/dig-beak.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.699', 159);
INSERT INTO cards.monsters VALUES (124, 'Dream Clown', 'DARK', NULL, '{Warrior,Normal}', 'Its sweet dancing lulls the viewer to an eternal sleep.', 1200, 900, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/dream-clown.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.7', 120);
