INSERT INTO cards.monsters VALUES (300, 'Wicked Dragon with', 'DARK', NULL, '{Dragon,Normal}', 'A two-headed dragon with a pair of jaws that can tear an enemy to shreds.', 900, 900, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/wicked-dragon-with.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.743', NULL);
