INSERT INTO cards.monsters VALUES (84, 'Megazowler', 'DARK', NULL, '{Dinosaur,Normal}', 'Nothing stands in the way of this spike-covered dinosaur!', 1800, 2000, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/megazowler.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.671', 79);
INSERT INTO cards.monsters VALUES (87, 'Castle of D. Magic', 'DARK', NULL, '{Fiend,Normal}', 'A creature that can generate darkness to envelop all that exists around it.', 920, 1930, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/castle-of-d-magic.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.673', 83);
INSERT INTO cards.monsters VALUES (92, 'Metal Guardian', 'DARK', NULL, '{Fiend,Normal}', 'A fiend guarding the treasures of the netherworld, it''s most at home in the dark.', 1150, 2150, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/metal-guardian.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.674', 88);
INSERT INTO cards.monsters VALUES (94, 'Gyakutenno Megami', 'DARK', NULL, '{Fairy,Normal}', 'Uses her holy power to protect the weak. This goddess has the power of reversal.', 1800, 2000, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/gyakutenno-megami.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.675', 90);
INSERT INTO cards.monsters VALUES (97, 'Zanki', 'DARK', NULL, '{Warrior,Normal}', 'Prefers to face enemies one-on-one. His swiftly drawn blade delivers a quick and immediate finish.', 1500, 1700, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/zanki.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.676', 93);
INSERT INTO cards.monsters VALUES (100, 'Armored Zombie', 'DARK', NULL, '{Zombie,Normal}', 'A warrior raised from the beyond. Blindly swings a sharp blade with devastating force.', 1500, 0, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/armored-zombie.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.677', 96);
INSERT INTO cards.monsters VALUES (103, 'Pumpking the King', 'DARK', NULL, '{Zombie,Normal}', 'This pumpkin king strikes at its enemies with its long tentacles.', 1800, 2000, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/pumpking-the-king.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.679', 99);
INSERT INTO cards.monsters VALUES (106, 'Mask of Darkness', 'DARK', NULL, '{Fiend,Normal}', 'A shadow mask created by the hands of a dark mage.', 900, 400, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/mask-of-darkness.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.68', 102);
INSERT INTO cards.monsters VALUES (112, 'Graveyard & Hand', 'DARK', NULL, '{Zombie,Normal}', 'A final resting place that enhances the power of the doomed and drains that of the living.', 700, 900, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/graveyard-hand.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.681', 108);
INSERT INTO cards.monsters VALUES (116, 'That Which Feeds', 'DARK', NULL, '{Fiend,Normal}', 'A demon that fuels its power by feeding on the souls of other creatures.', 1200, 1000, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/that-which-feeds.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.683', 112);
INSERT INTO cards.monsters VALUES (119, 'Kamionwizard', 'DARK', NULL, '{Spellcaster,Normal}', 'A magic-user that controls chaos and wields a mighty sickle.', 1300, 1100, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/kamionwizard.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.684', 115);
INSERT INTO cards.monsters VALUES (121, 'Spirit of the Book', 'DARK', NULL, '{WingedBeast,Normal}', 'A spirit of the book with infinite knowledge and an endless variety of attack strategies.', 1400, 1200, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/spirit-of-the-book.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.685', 117);
INSERT INTO cards.monsters VALUES (89, 'King of Yamimakai', 'DARK', NULL, '{Fiend,Normal}', 'Wields the power of darkness to destroy its enemies.', 2000, 1530, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/king-of-yamimakai.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.686', 85);
INSERT INTO cards.monsters VALUES (115, 'Doma The Angel of', 'DARK', NULL, '{Fairy,Normal}', 'The angel of death. This being must never be angered. To earn its wrath is to know death.', 1600, 1400, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/doma-the-angel-of.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.687', 111);
INSERT INTO cards.monsters VALUES (127, 'Dark Plant', 'DARK', NULL, '{Plant,Normal}', 'A malignant flower grown in polluted soil with dark powers. It is extremely wild and vicious.', 300, 400, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/dark-plant.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.688', 123);
INSERT INTO cards.monsters VALUES (132, 'LaMoon', 'DARK', NULL, '{Spellcaster,Normal}', 'A sorcerer who lives on the moon and attacks opponents with the power of lunar light.', 1200, 1700, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/lamoon.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.689', 128);
INSERT INTO cards.monsters VALUES (135, 'Octoberser', 'DARK', NULL, '{Aqua,Normal}', 'With the head of a fish and the legs of an octopus, this strange creature attacks enemies by flinging spears.', 1600, 1400, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/octoberser.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.69', 131);
INSERT INTO cards.monsters VALUES (138, 'Mystical Capture C', 'DARK', NULL, '{Fairy,Normal}', 'A mystical chain that is believed capable of binding its enemies and preventing their attacks.', 700, 700, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/mystical-capture-c.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.692', 134);
INSERT INTO cards.monsters VALUES (141, 'Mystery Hand', 'DARK', NULL, '{Fiend,Normal}', 'This monster twists reality and reaches between dimensions to attack its enemies.', 500, 500, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/mystery-hand.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.693', 137);
INSERT INTO cards.monsters VALUES (144, 'Toad Master', 'DARK', NULL, '{Aqua,Normal}', 'A frog that has lived thousands of years. It attacks with tadpoles.', 1000, 1000, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/toad-master.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.694', 140);
INSERT INTO cards.monsters VALUES (149, 'Temple of Skulls', 'DARK', NULL, '{Zombie,Normal}', 'A mysterious temple of skulls and bones that pulls in unsuspecting enemies.', 900, 1300, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/temple-of-skulls.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.695', 146);
INSERT INTO cards.monsters VALUES (153, 'Akihiron', 'DARK', NULL, '{Aqua,Normal}', 'A mysterious creature that dwells below the sea.', 1700, 1400, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/akihiron.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.697', 150);
INSERT INTO cards.monsters VALUES (155, 'The Melting Red Sh', 'DARK', NULL, '{Aqua,Normal}', 'A creature that melts into the earth then melds with an opponent''s shadow, and attacks from below.', 500, 700, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/the-melting-red-sh.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.697', 152);
INSERT INTO cards.monsters VALUES (161, 'Man Eater', 'DARK', NULL, '{Plant,Normal}', 'Man-eating plant with poison feelers for attacking enemies.', 800, 600, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/man-eater.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.699', 158);
INSERT INTO cards.monsters VALUES (122, 'Supporter in the S', 'DARK', NULL, '{Warrior,Normal}', 'A cute elf that assists against enemies while remaining hidden from sight.', 1000, 1000, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/supporter-in-the-s.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.7', 118);
INSERT INTO cards.monsters VALUES (128, 'Ancient Tool', 'DARK', NULL, '{Machine,Normal}', 'A machine that was found in the ruins of an ancient culture. It appears to have been made solely to destroy.', 1700, 1400, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/ancient-tool.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.701', 124);
INSERT INTO cards.monsters VALUES (167, 'Lord of Zemia', 'DARK', NULL, '{Fiend,Normal}', 'A wicked entity that manipulates enemies towards a path of destruction.', 1300, 1000, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/lord-of-zemia.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.702', 164);
INSERT INTO cards.monsters VALUES (170, 'Ancient Jar', 'DARK', NULL, '{Rock,Normal}', 'A very fragile ancient jar. Something appears to lurk within.', 400, 200, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/ancient-jar.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.703', 167);
INSERT INTO cards.monsters VALUES (172, 'Dark King of the A', 'DARK', NULL, '{Fiend,Normal}', 'It''s said that this King of the Netherworld once had the power to rule over the dark.', 1200, 800, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/dark-king-of-the-a.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.704', 169);
INSERT INTO cards.monsters VALUES (176, 'Dark Prisoner', 'DARK', NULL, '{Fiend,Normal}', 'This monster bends light to hide its image from the eyes of opponents.', 600, 1000, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/dark-prisoner.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.705', 173);
INSERT INTO cards.monsters VALUES (180, 'Monsturtle', 'DARK', NULL, '{Aqua,Normal}', 'Protected by a spiked shell, this turtle has a very nasty disposition.', 800, 1000, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/monsturtle.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.706', 177);
INSERT INTO cards.monsters VALUES (183, 'Arlownay', 'DARK', NULL, '{Plant,Normal}', 'A female being that lurks in a flower to cast toxic dust. She is very dangerous and must not be approached.', 800, 1000, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/arlownay.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.707', 180);
INSERT INTO cards.monsters VALUES (186, 'Lucky Trinket', 'DARK', NULL, '{Spellcaster,Normal}', 'This creature may look slim and weak, but it is protected by a sacred force.', 600, 800, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/lucky-trinket.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.708', 183);
INSERT INTO cards.monsters VALUES (189, 'Fiend Reflection#2', 'DARK', NULL, '{WingedBeast,Normal}', 'A bird-beast that summons reinforcements with a hand mirror.', 1100, 1400, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/fiend-reflection-2.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.71', 186);
INSERT INTO cards.monsters VALUES (192, 'Fusionist', 'DARK', NULL, '{Beast,Normal}', 'A feline monster that has angelic wings and a long tail.', 900, 700, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/fusionist.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.711', 189);
INSERT INTO cards.monsters VALUES (195, 'Key Mace', 'DARK', NULL, '{Fairy,Normal}', 'Enemies'' hearts will melt at the sight of this small fairy''s cuteness.', 400, 300, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/key-mace.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.711', 192);
INSERT INTO cards.monsters VALUES (198, 'Doron', 'DARK', NULL, '{Warrior,Normal}', 'This monster splits in two and attacks from opposite sides.', 900, 500, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/doron.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.712', 195);
INSERT INTO cards.monsters VALUES (201, 'Happy Lover', 'DARK', NULL, '{Fairy,Normal}', 'Enemies become overjoyed when struck by the Heart Ray emitted from the forehead of this tiny cherub.', 800, 500, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/happy-lover.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.713', 198);
INSERT INTO cards.monsters VALUES (204, 'Frenzied Panda', 'DARK', NULL, '{Beast,Normal}', 'A savage beast that carries a big bamboo stick for beating down its enemies.', 1200, 1000, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/frenzied-panda.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.714', 201);
INSERT INTO cards.monsters VALUES (174, 'Big Eye', 'DARK', NULL, '{Fiend,Normal}', 'This creature is covered with hypnotic eyes for mesmerizing its enemies.', 1200, 1000, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/big-eye.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.715', 171);
INSERT INTO cards.monsters VALUES (211, 'Petit Angel', 'DARK', NULL, '{Fairy,Normal}', 'A quick-moving and tiny fairy that''s very difficult to hit.', 600, 900, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/petit-angel.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.716', 208);
INSERT INTO cards.monsters VALUES (218, 'Flame Ghost', 'DARK', NULL, '{Zombie,Normal}', 'A ghost of someone who was burned to death. The flames enshrouding its body burn everything.', 1000, 800, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/flame-ghost.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.717', 215);
