INSERT INTO cards.monsters VALUES (225, 'Midnight Fiend', 'DARK', NULL, '{Fiend,Normal}', 'This monster only appears when a midnight tribute is made.', 800, 600, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/midnight-fiend.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.719', 222);
INSERT INTO cards.monsters VALUES (230, 'Hitodenchak', 'DARK', NULL, '{Aqua,Normal}', 'A rabid starfish that spits a lethal acid that can melt almost anything.', 600, 700, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/hitodenchak.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.721', 227);
INSERT INTO cards.monsters VALUES (233, 'Rare Fish', 'DARK', NULL, '{Fish,Normal}', 'An unusual and ferocious fish with the head of a beast.', 1500, 1200, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/rare-fish.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.722', 230);
INSERT INTO cards.monsters VALUES (235, 'Madjinn Gunn', 'DARK', NULL, '{Fiend,Normal}', 'A biological weapon that attacks by firing projectiles from its mouth.', 600, 800, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/madjinn-gunn.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.723', 232);
INSERT INTO cards.monsters VALUES (239, 'Guardian of the La', 'DARK', NULL, '{Warrior,Normal}', 'A warrior that guards the entrance to the netherworld. It cuts down mercilessly anyone without the authority to pass.', 1000, 1200, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/guardian-of-the-la.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.724', 236);
INSERT INTO cards.monsters VALUES (243, 'The Drdek', 'DARK', NULL, '{Fiend,Normal}', 'A monster who grew a leg in the eyeball. It can jump high and attacks with its claws.', 700, 800, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/the-drdek.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.725', 240);
INSERT INTO cards.monsters VALUES (213, 'Hinotama Soul', 'DARK', NULL, '{Pyro,Normal}', 'An intensely hot flame creature that rams anything that stands in its way.', 600, 500, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/hinotama-soul.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.725', 344);
INSERT INTO cards.monsters VALUES (208, 'Dorover', 'DARK', NULL, '{Aqua,Normal}', 'A disgusting muddy monster. It attacks by spewing toxic gas.', 900, 800, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/dorover.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.726', 205);
INSERT INTO cards.monsters VALUES (223, 'Masked Sorcerer', 'DARK', NULL, '{Spellcaster,Normal}', 'A mysterious wizard whose face remains forever hidden behind a strange mask.', 900, 1400, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/masked-sorcerer.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.727', 220);
INSERT INTO cards.monsters VALUES (241, 'Yashinoki', 'DARK', NULL, '{Plant,Normal}', 'An animated palm tree. It attacks by dropping fruit that contain tasty milk.', 800, 600, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/yashinoki.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.728', 238);
INSERT INTO cards.monsters VALUES (250, 'Root Water', 'DARK', NULL, '{Fish,Normal}', 'An amphibian capable of calling up a massive tidal wave from the dark seas to wipe out enemy monsters.', 900, 800, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/root-water.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.729', 247);
INSERT INTO cards.monsters VALUES (253, 'Hyo', 'DARK', NULL, '{Warrior,Normal}', 'A warrior whose whole body is made of ice. His touch will freeze anything.', 800, 1200, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/hyo.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.73', 250);
INSERT INTO cards.monsters VALUES (256, 'Angelwitch', 'DARK', NULL, '{Spellcaster,Normal}', 'Although destined to be an angel, this creature chose the way of the witch instead.', 800, 1000, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/angelwitch.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.732', 253);
INSERT INTO cards.monsters VALUES (260, 'Stone Armadiller', 'DARK', NULL, '{Rock,Normal}', 'With a body armored by rock-hard fur, this monster features excellent defense capabilities.', 800, 1200, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/stone-armadiller.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.733', 257);
INSERT INTO cards.monsters VALUES (265, 'Swordsman of Aile', 'DARK', NULL, '{Warrior,Normal}', 'A dwarf who serves the traveler Aile. He rides a lizard warrior into battle.', 800, 1300, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/swordsman-of-aile.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.734', 262);
INSERT INTO cards.monsters VALUES (267, 'Wing Egg Elf', 'DARK', NULL, '{Fairy,Normal}', 'This fairy in an eggshell uses massive wings to blow back almost any projectile attack.', 500, 1300, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/wing-egg-elf.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.734', 264);
INSERT INTO cards.monsters VALUES (270, 'Unknown Warrior', 'DARK', NULL, '{Warrior,Normal}', 'A warrior who creates a vacuum at high speed to tear at the foe.', 1000, 500, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/unknown-warrior.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.735', 267);
INSERT INTO cards.monsters VALUES (275, 'Mavelus', 'DARK', NULL, '{WingedBeast,Normal}', 'A type of a fiery bird that makes its home in high mountains. It sprays fire from its mouth to burn everything around it.', 1300, 900, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/mavelus.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.737', 272);
INSERT INTO cards.monsters VALUES (278, 'Terra Bugroth', 'DARK', NULL, '{Machine,Normal}', 'A surface battle robot. It appears to have been usable in the sea, but no longer.', 1500, 1000, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/terra-bugroth.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.738', 275);
INSERT INTO cards.monsters VALUES (282, 'King Fog', 'DARK', NULL, '{Fiend,Normal}', 'A fiend that dwells in a blinding curtain of smoke.', 1000, 900, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/king-fog.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.739', 279);
INSERT INTO cards.monsters VALUES (286, 'Holograh', 'DARK', NULL, '{Machine,Normal}', 'This machine generates illusions that leave an enemy wide open to attacks.', 1100, 700, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/holograh.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.741', 283);
INSERT INTO cards.monsters VALUES (263, 'Lunar Queen Elzaim', 'DARK', NULL, '{Fairy,Normal}', 'A beautiful goddess guarded by the moon. Her lunar curtain can block attacks.', 750, 1100, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/lunar-queen-elzaim.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.741', 260);
INSERT INTO cards.monsters VALUES (280, 'Gorgon Egg', 'DARK', NULL, '{Fiend,Normal}', 'An egg laid by a Gorgon. It is sad that whatever is reflected in its eye is what will hatch.', 300, 1300, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/gorgon-egg.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.742', 277);
INSERT INTO cards.monsters VALUES (290, 'Ogre of the Black', 'DARK', NULL, '{BeastWarrior,Normal}', 'An ogre that has been possessed by a black shadow. It attacks at an astounding speed.', 1200, 1400, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/ogre-of-the-black.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.744', 287);
INSERT INTO cards.monsters VALUES (293, 'Moon Envoy', 'DARK', NULL, '{Warrior,Normal}', 'A servant of the moon goddess, This warrior wields a pike with a spectacular crescent-shaped blade.', 1100, 1000, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/moon-envoy.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.745', 290);
INSERT INTO cards.monsters VALUES (296, 'Dragoness the Wick', 'DARK', NULL, '{Warrior,Normal}', 'A winged knight that gained power through dragon equipment. It hacks at foes from the sky, diving repeatedly.', 1200, 900, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/dragoness-the-wick.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.747', 294);
INSERT INTO cards.monsters VALUES (301, 'Sonic Maid', 'DARK', NULL, '{Warrior,Normal}', 'A maiden that uses sound to her advantage, she wields a scythe that''s shaped like a musical note.', 1200, 900, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/sonic-maid.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.748', 299);
INSERT INTO cards.monsters VALUES (306, 'Stuffed Animal', 'DARK', NULL, '{Warrior,Normal}', 'It may look like a harmless stuffed animal, but its zipper mouth deals a deadly bite.', 1200, 900, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/stuffed-animal.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.749', 354);
INSERT INTO cards.monsters VALUES (310, 'Seiyaryu', 'DARK', NULL, '{Dragon,Normal}', 'A mystical dragon that burns away the wicked with its mystic flames.', 2500, 2300, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/seiyaryu.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.75', 358);
INSERT INTO cards.monsters VALUES (313, 'Flying Penguin', 'DARK', NULL, '{Aqua,Normal}', 'A very rare penguin that takes to the air with ears shaped like wings.', 1200, 1000, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/flying-penguin.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.751', 361);
INSERT INTO cards.monsters VALUES (316, 'B. Luster Soldier', 'DARK', NULL, '{Warrior,Normal}', 'A powerful warrior with the same capabilities as the legendary B-Eye White Dragon.', 3000, 2500, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/b-luster-soldier.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.752', 364);
INSERT INTO cards.monsters VALUES (40, 'Rock Ogre Grotto#1', 'DARK', NULL, '{Rock,Normal}', 'Protected by a solid body of rock, this creature throws a bone-shattering punch.', 800, 1200, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/rock-ogre-grotto-1.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.753', 28);
INSERT INTO cards.monsters VALUES (63, 'Larvae Moth', 'DARK', NULL, '{Insect,Normal}', 'This monster cannot be Normal Summoned or Set. This card can only be Special Summoned by offering "Petit Moth" as a Tribute on the 2nd of your turns after "Petit Moth" has been equipped with "Cocoon of Evolution". ', 500, 400, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/larvae-moth.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.754', 56);
INSERT INTO cards.monsters VALUES (298, 'One-eyed Shield Dr', 'DARK', NULL, '{Dragon,Normal}', 'This dragon wears a shield not only for its own protection, but also for ramming its enemies.', 700, 1300, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/one-eyed-shield-dr.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.755', 296);
INSERT INTO cards.monsters VALUES (1, 'Blue-Eyes White Dragon', 'LIGHT', 8, '{Dragon,Normal}', 'This legendary dragon is a powerful engine of destruction. Virtually invincible, very few have faced this awesome creature and lived to tell the tale.', 3000, 2500, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/blue-eyes-white-dragon.png', '2026-06-19 22:05:56.582', '2026-06-24 01:39:40.757', 1);
INSERT INTO cards.monsters VALUES (130, 'Orion the Battle K', 'DARK', NULL, '{Fairy,Normal}', 'An imposing angel that is claimed to be the god of battle. No one, however, has been witness to it in battle.', 1800, 1500, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/orion-the-battle-k.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.758', 126);
INSERT INTO cards.monsters VALUES (163, 'M-warrior #1', 'DARK', NULL, '{Warrior,Normal}', 'Specializing in combination attacks, this warrior uses magnetism to block an enemy''s escape.', 1000, 500, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/m-warrior-1.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.759', 160);
INSERT INTO cards.monsters VALUES (197, 'Terra the Terrible', 'DARK', NULL, '{Fiend,Normal}', 'A swamp-dwelling minion of the dark forces. While it is not as strong as it looks, don''t treat it lightly.', 1200, 1300, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/terra-the-terrible.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.76', 194);
INSERT INTO cards.monsters VALUES (229, 'Skull Stalker', 'DARK', NULL, '{Warrior,Normal}', 'Swift and vicious, this monster grabs its victim with its pincers and attack the captive with its poison stinger.', 900, 800, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/skull-stalker.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.761', 226);
INSERT INTO cards.monsters VALUES (264, 'Archfiend Mirror', 'DARK', NULL, '{Fiend,Normal}', 'A wicked mirror that hypnotizes enemies, diverting attacks from their intended targets.', 700, 600, 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/archfiend-mirror.png', '2026-06-20 23:03:16.298', '2026-06-24 01:39:40.762', 261);
