INSERT INTO cards.spells VALUES (2, 'Sword of Dark', 302, 'Equip', 'A warrior who has sold their soul to evil can strengthened with the power of darkness.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/sword-of-dark.png', '2026-06-26 03:58:19.984', '2026-06-27 04:39:32.741');
INSERT INTO cards.spells VALUES (3, 'Dark Energy', 303, 'Equip', 'Fiends and other monsters of the dark power up by 60%!', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/dark-energy.png', '2026-06-26 03:58:19.985', '2026-06-27 04:39:32.742');
INSERT INTO cards.spells VALUES (4, 'Axe of Despair', 304, 'Equip', 'Fiends and Beast-Warriors can constantly use their maximum strength.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/axe-of-despair.png', '2026-06-26 03:58:19.985', '2026-06-27 04:39:32.743');
INSERT INTO cards.spells VALUES (5, 'Lazer Cannon Armor', 305, 'Equip', 'If equipped by an insect, etc. it can fire powerful beams.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/lazer-cannon-armor.png', '2026-06-26 03:58:19.986', '2026-06-27 04:39:32.744');
INSERT INTO cards.spells VALUES (6, 'Insect Armor Laser', 306, 'Equip', 'Shoots intense flames. Can only be equipped with insects, etc.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/insect-armor-laser.png', '2026-06-26 03:58:19.986', '2026-06-27 04:39:32.744');
INSERT INTO cards.spells VALUES (8, 'Beast Fangs', 308, 'Equip', 'Increases the power of Beasts and other fanged monsters.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/beast-fangs.png', '2026-06-26 03:58:19.987', '2026-06-27 04:39:32.747');
INSERT INTO cards.spells VALUES (10, 'Vile Germs', 310, 'Equip', 'Vile microbes boosts the power of Plants in the woods!', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/vile-germs.png', '2026-06-26 03:58:19.989', '2026-06-27 04:39:32.748');
INSERT INTO cards.spells VALUES (11, 'Black Pendant', 311, 'Equip', 'Dark wizards are powered up when wearing this pendant.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/black-pendant.png', '2026-06-26 03:58:19.989', '2026-06-27 04:39:32.748');
INSERT INTO cards.spells VALUES (13, 'Horn of Light', 313, 'Equip', 'Increases the power of horned creatures. Has no effect on Dark monsters.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/horn-of-light.png', '2026-06-26 03:58:19.99', '2026-06-27 04:39:32.749');
INSERT INTO cards.spells VALUES (15, 'Dragon Treasure', 315, 'Equip', 'A legendary treasure that increases the power of dragons.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/dragon-treasure.png', '2026-06-26 03:58:19.991', '2026-06-27 04:39:32.75');
INSERT INTO cards.spells VALUES (17, 'Cyber Shield', 317, 'Equip', 'Increases the power of female monsters by changing their attitudes!', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/cyber-shield.png', '2026-06-26 03:58:19.992', '2026-06-27 04:39:32.751');
INSERT INTO cards.spells VALUES (18, 'Elegant Egotist', 318, 'Normal', 'Creates the doppelgangers of Harpie Lady for three-pronged attacks.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/elegant-egotist.png', '2026-06-26 03:58:19.993', '2026-06-27 04:39:32.752');
INSERT INTO cards.spells VALUES (20, 'Stop Defense', 320, 'Normal', 'Forces an opponent''s Defense Position monster into Attack Position.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/stop-defense.png', '2026-06-26 03:58:19.994', '2026-06-27 04:39:32.752');
INSERT INTO cards.spells VALUES (22, 'Violet Crystal', 322, 'Equip', 'Mystic forces from the crystal increase the power of Zombies.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/violet-crystal.png', '2026-06-26 03:58:19.995', '2026-06-27 04:39:32.753');
INSERT INTO cards.spells VALUES (24, 'Invigoration', 324, 'Equip', 'Increases the power of Thunder, Rock and Pyro monsters!', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/invigoration.png', '2026-06-26 03:58:19.996', '2026-06-27 04:39:32.754');
INSERT INTO cards.spells VALUES (25, 'Machine Conversion', 325, 'Equip', 'A manufacturing facility that tunes up all Machine monsters.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/machine-conversion.png', '2026-06-26 03:58:19.996', '2026-06-27 04:39:32.755');
INSERT INTO cards.spells VALUES (27, 'Follow Wind', 327, 'Equip', 'The winds provide support to increase the power of Winged Beasts and other flying monsters!', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/follow-wind.png', '2026-06-26 03:58:19.997', '2026-06-27 04:39:32.756');
INSERT INTO cards.spells VALUES (29, 'Dragon Capture Jar', 329, 'Continuous', 'Seals all Dragon-Type monsters on the field.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/dragon-capture-jar.png', '2026-06-26 03:58:19.999', '2026-06-27 04:39:32.756');
INSERT INTO cards.spells VALUES (30, 'Forest', 330, 'Field', 'Changes the field to a verdant forest that benefits Insects and Beasts.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/forest.png', '2026-06-26 03:58:19.999', '2026-06-27 04:39:32.757');
INSERT INTO cards.spells VALUES (32, 'Mountain', 332, 'Field', 'Changes the field into a vast mountain range that benefits Dragons and Winged Beasts!', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/mountain.png', '2026-06-26 03:58:20', '2026-06-27 04:39:32.758');
INSERT INTO cards.spells VALUES (34, 'Umi', 334, 'Field', 'Changes the field to a sea. Water monsters power up!', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/umi.png', '2026-06-26 03:58:20.001', '2026-06-27 04:39:32.759');
INSERT INTO cards.spells VALUES (35, 'Yami', 335, 'Field', 'Transforms the field into darkness, benefiting Spellcasters!', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/yami.png', '2026-06-26 03:58:20.002', '2026-06-27 04:39:32.759');
INSERT INTO cards.spells VALUES (37, 'Raigeki', 337, 'Normal', 'Destroy every opposing monster with a stroke of lightning!', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/raigeki.png', '2026-06-26 03:58:20.003', '2026-06-27 04:39:32.76');
INSERT INTO cards.spells VALUES (39, 'Red Medicine', 339, 'Normal', 'A magic potion that increases Life Points by 500.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/red-medicine.png', '2026-06-26 03:58:20.003', '2026-06-27 04:39:32.761');
INSERT INTO cards.spells VALUES (41, 'Soul of the Pure', 341, 'Normal', 'The blood of an angel that she collected by injuring herself. It restores 2000 Life Points.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/soul-of-the-pure.png', '2026-06-26 03:58:20.004', '2026-06-27 04:39:32.761');
INSERT INTO cards.spells VALUES (43, 'Sparks', 343, 'Normal', 'A shower of sparks inflicts 200 points of damage to your opponent''s Life Points.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/sparks.png', '2026-06-26 03:58:20.005', '2026-06-27 04:39:32.762');
INSERT INTO cards.spells VALUES (44, 'Hinotama', 344, 'Normal', 'A fireball inflicts 500 points of damage to your opponent''s Life Points.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/hinotama.png', '2026-06-26 03:58:20.006', '2026-06-27 04:39:32.763');
INSERT INTO cards.spells VALUES (46, 'Ookazi', 346, 'Normal', 'A huge blaze that burns all day inflicts 2000 damage to your opponent''s Life Points.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/ookazi.png', '2026-06-26 03:58:20.007', '2026-06-27 04:39:32.763');
INSERT INTO cards.spells VALUES (48, 'Swords Revealing', 348, 'Normal', 'Enemy monsters are revealed and your opponent cannot attack for three turns.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/swords-revealing.png', '2026-06-26 03:58:20.008', '2026-06-27 04:39:32.764');
INSERT INTO cards.spells VALUES (49, 'Spellbind Circle', 349, 'Continuous', 'The curse of the hexagram reduces the power of all the opponent''s monsters.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/spellbind-circle.png', '2026-06-26 03:58:20.008', '2026-06-27 04:39:32.764');
INSERT INTO cards.spells VALUES (1, 'Legendary Sword', 301, 'Equip', 'An enchanted sword that can draw out the powers of a warrior. It cannot be used by servants of the dark.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/legendary-sword.png', '2026-06-26 03:58:19.957', '2026-06-27 04:39:32.735');
INSERT INTO cards.spells VALUES (7, 'Elf''s Light', 307, 'Equip', 'The holy light of the spirit powers up elves.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/elf-s-light.png', '2026-06-26 03:58:19.987', '2026-06-27 04:39:32.745');
INSERT INTO cards.spells VALUES (9, 'Steel Shell', 309, 'Equip', 'Boosts the power of shelled monsters. Said to have no effect on those without shells.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/steel-shell.png', '2026-06-26 03:58:19.988', '2026-06-27 04:39:32.747');
INSERT INTO cards.spells VALUES (12, 'Silver Bow & Arrow', 312, 'Equip', 'A silver bow, when equipped can power up a fairy, etc.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/silver-bow-arrow.png', '2026-06-26 03:58:19.99', '2026-06-27 04:39:32.749');
INSERT INTO cards.spells VALUES (14, 'Horn of Unicorn', 314, 'Equip', 'Increases the power of Dark monsters with horns on their head!', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/horn-of-unicorn.png', '2026-06-26 03:58:19.991', '2026-06-27 04:39:32.75');
INSERT INTO cards.spells VALUES (16, 'Electro-Whip', 316, 'Equip', 'A whip for paralyzing enemies. Increases power when equipped with female etc.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/electro-whip.png', '2026-06-26 03:58:19.992', '2026-06-27 04:39:32.751');
INSERT INTO cards.spells VALUES (19, 'Mystical Moon', 319, 'Equip', 'Magical powers of the moonlight increases the power of Beasts and makes them savage.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/mystical-moon.png', '2026-06-26 03:58:19.994', '2026-06-27 04:39:32.752');
INSERT INTO cards.spells VALUES (21, 'Malevolent Nuzzler', 321, 'Equip', 'Female and Dark monsters are powered up by demonic forces.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/malevolent-nuzzler.png', '2026-06-26 03:58:19.995', '2026-06-27 04:39:32.753');
INSERT INTO cards.spells VALUES (23, 'Book of Secret Art', 323, 'Equip', 'A magic book for increasing the power of magicians. It cannot be read by anyone with evil in their heart.', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/book-of-secret-art.png', '2026-06-26 03:58:19.995', '2026-06-27 04:39:32.754');
INSERT INTO cards.spells VALUES (26, 'Raise Body Heat', 326, 'Equip', 'Absorbs the sun''s energy to increase the power of Dinosaurs!', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/raise-body-heat.png', '2026-06-26 03:58:19.997', '2026-06-27 04:39:32.755');
INSERT INTO cards.spells VALUES (28, 'Power of Kaishin', 328, 'Equip', 'Poseidon''s strength is shared to boost the power of Aqua, Fish and Sea Serpent monsters', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/power-of-kaishin.png', '2026-06-26 03:58:19.998', '2026-06-27 04:39:32.756');
INSERT INTO cards.spells VALUES (31, 'Wasteland', 331, 'Field', 'Changes the field into a desolate wasteland that benefits Dinosaurs and Zombies!', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/wasteland.png', '2026-06-26 03:58:20', '2026-06-27 04:39:32.757');
INSERT INTO cards.spells VALUES (33, 'Sogen', 333, 'Field', 'Changes the field to a meadow, as far as the eye can see. Warriors power up!', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/sogen.png', '2026-06-26 03:58:20.001', '2026-06-27 04:39:32.758');
INSERT INTO cards.spells VALUES (36, 'Dark Hole', 336, 'Normal', 'Mercilessly inhales all monsters on the field!', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/dark-hole.png', '2026-06-26 03:58:20.002', '2026-06-27 04:39:32.759');
INSERT INTO cards.spells VALUES (38, 'Mooyan Curry', 338, 'Normal', 'A delicious beef curry increases Life Points by 200', 'https://ppgcevlcwiwxcstjzxvv.supabase.co/storage/v1/object/public/duel-monster-images/mooyan-curry.png', '2026-06-26 03:58:20.003', '2026-06-27 04:39:32.76');
